prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?modelId . }
  FILTER(CONTAINS(STR(?modelId), "3c08e52742754da6a4065fc5787131dc") || CONTAINS(STR(?model), "3c08e52742754da6a4065fc5787131dc"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?modelId ?origId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(CONTAINS(STR(?modelId), "3c08e527") || CONTAINS(STR(?origId), "3c08e527") || CONTAINS(STR(?model), "3c08e527"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?incoming ?outgoing WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  ?task bbo:name ?taskName .

  # Count incoming flows
  {
    SELECT ?task (COUNT(DISTINCT ?inFlow) as ?incoming) WHERE {
      ?inFlow a bbo:SequenceFlow .
      ?inFlow bbo:has_targetRef ?task .
    }
    GROUP BY ?task
  }

  # Count outgoing flows
  {
    SELECT ?task (COUNT(DISTINCT ?outFlow) as ?outgoing) WHERE {
      ?outFlow a bbo:SequenceFlow .
      ?outFlow bbo:has_sourceRef ?task .
    }
    GROUP BY ?task
  }
}
LIMIT 50
